import React from 'react';
import { Link } from 'react-router-dom';
import { StatusBadge } from '@linm-soft/common-components';
import type { PeriodProcessDocumentsDto, PeriodProcessJournalDto } from '../../services/kt/models';
import { ktPdcId } from '../../router/paths';
import { formatDateLocal, formatVnd } from '../../utils/formatters';
import df from '../../styles/documentForm.module.css';
import erp from '../../styles/erpPage.module.css';

export interface PeriodProcessDocumentsSectionProps {
  documents: PeriodProcessDocumentsDto | null;
  loading?: boolean;
  testIdPrefix: string;
  emptyMessage?: string;
}

const JournalBlock: React.FC<{ journal: PeriodProcessJournalDto; testIdPrefix: string }> = ({
  journal,
  testIdPrefix,
}) => (
  <div className={df.section} data-testid={`${testIdPrefix}-journal-${journal.id}`}>
    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8, flexWrap: 'wrap' }}>
      <strong>
        <Link
          to={ktPdcId(journal.id)}
          data-testid={`${testIdPrefix}-journal-link-${journal.id}`}
          style={{ textDecoration: 'none' }}
        >
          <code>{journal.code}</code>
        </Link>
      </strong>
      <StatusBadge status={journal.status} />
      <span style={{ fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}>
        {formatDateLocal(journal.entryDate)}
      </span>
    </div>
    {journal.description && (
      <p style={{ margin: '0 0 8px', fontSize: 13 }}>{journal.description}</p>
    )}
    <div className={erp.tableWrapper}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th>TK Nợ</th>
            <th>TK Có</th>
            <th>Diễn giải</th>
            <th>Mã VT</th>
            <th className={erp.colRight}>Số tiền</th>
          </tr>
        </thead>
        <tbody>
          {journal.lines.map((line, i) => (
            <tr key={i}>
              <td><code>{line.debitAccountCode}</code></td>
              <td><code>{line.creditAccountCode}</code></td>
              <td>{line.description ?? '—'}</td>
              <td>{line.materialCode ? <code>{line.materialCode}</code> : '—'}</td>
              <td className={erp.colRight}>{formatVnd(line.amount)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  </div>
);

export const PeriodProcessDocumentsSection: React.FC<PeriodProcessDocumentsSectionProps> = ({
  documents,
  loading,
  testIdPrefix,
  emptyMessage = 'Chưa có bút toán — chạy tính toán để xem chi tiết phương pháp và dòng hạch toán.',
}) => {
  if (loading) {
    return (
      <div className={df.section} data-testid={`${testIdPrefix}-documents-loading`}>
        <p style={{ margin: 0, fontSize: 13 }}>Đang tải bút toán…</p>
      </div>
    );
  }

  if (!documents || documents.journals.length === 0) {
    return (
      <div className={df.section} data-testid={`${testIdPrefix}-documents-empty`}>
        <h2 className={df.sectionTitle}>Kết quả hạch toán</h2>
        <p style={{ margin: 0, fontSize: 13, color: 'var(--color-text-secondary, #6c757d)' }}>{emptyMessage}</p>
      </div>
    );
  }

  return (
    <div data-testid={`${testIdPrefix}-documents`}>
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Phương pháp tính</h2>
        {documents.methodDescription && (
          <p style={{ margin: 0, fontSize: 13, lineHeight: 1.5 }} data-testid={`${testIdPrefix}-method`}>
            {documents.methodDescription}
          </p>
        )}
        <p style={{ margin: '8px 0 0', fontSize: 12, color: 'var(--color-text-secondary, #6c757d)' }}>
          Mã tham chiếu: <code>{documents.referenceNo}</code> · {documents.journals.length} phiếu kế toán
        </p>
      </div>
      {documents.journals.map(j => (
        <JournalBlock key={j.id} journal={j} testIdPrefix={testIdPrefix} />
      ))}
    </div>
  );
};
